#include <bits/stdc++.h>
using namespace std;
bool check(char x,char y){
    if(x>='a' && x<='z' && y>='a' && y<='z' && x<y)
        return true;
    if(x>='0' && x<='9' && y>='0' && y<='9' && x<y)
        return true;
    return false;
}
int main(){
    int p1,p2,p3;
    string s;
    ios::sync_with_stdio(false);
    cin.tie(0),cout.tie(0);
    cin>>p1>>p2>>p3;
    cin>>s;
    int n=s.size();
    s=" "+s;
    for(int i=1;i<=n;i++){
        if(s[i]=='-' && i<n && check(s[i-1],s[i+1])){
            if(p3==1){
                char c=s[i-1]+1;
                while(c<s[i+1]){
                    for(int i=1;i<=p2;i++){
                        if(p1==3)
                            cout<<"*";
                        else if(p1==2 && c>='a' && c<='z')
                            cout<<char(c-32);
                        else
                            cout<<c;
                    }
                    c++;
                }
            }else{
                char c=s[i+1]-1;
                while(c>s[i-1]){
                    for(int i=1;i<=p2;i++){
                        if(p1==3)
                            cout<<"*";
                        else if(p1==2 && c>='a' && c<='z')
                            cout<<char(c-32);
                        else
                            cout<<c;
                    }
                    c--;
                }
            }
        }else
            cout<<s[i];
    }
    return 0;
}
